"use strict";(self.webpackChunkleetcode=self.webpackChunkleetcode||[]).push([[9390],{3671:e=>{e.exports=JSON.parse('{"tag":{"label":"greedy","permalink":"/leetcode/pt-BR/docs/tags/greedy","allTagsPath":"/leetcode/pt-BR/docs/tags","count":14,"items":[{"id":"problems/assign-cake","title":"Assign Cake","description":"This question is asked by Amazon. You are at a birthday party and are asked to distribute cake to your guests. Each guest is only satisfied if the size of the piece of cake they\'re given matches their appetite (i.e., is greater than or equal to their appetite). Given two arrays, appetite and cake where the ith element of appetite represents the ith guest\'s appetite, and the elements of cake represents the sizes of cake you have to distribute, return the maximum number of guests that you can satisfy.","permalink":"/leetcode/pt-BR/docs/problems/assign-cake"},{"id":"problems/balanced-meals","title":"Balanced Meals","description":"This question is asked by Apple. You are serving people in a lunch line and need to ensure each person gets a \\"balanced\\" meal. A balanced meal is a meal where there exists the same number of food items as drink items. Someone is helping you prepare the meals and hands you food items (i.e. F) or a drink items (D) in the order specified by the items string. Return the maximum number of balanced meals you are able to create without being able to modify items.","permalink":"/leetcode/pt-BR/docs/problems/balanced-meals"},{"id":"problems/best-time-to-buy-and-sell-stock-ii","title":"Best Time to Buy and Sell Stock II","description":"You are given the list of prices of a particular stock. Each element in the array represents the price of the stock at a given second throughout the current day. Return the maximum profit you can make trading this stock.","permalink":"/leetcode/pt-BR/docs/problems/best-time-to-buy-and-sell-stock-ii"},{"id":"problems/boats-to-save-people","title":"Boats to Save People","description":"This question is asked by Amazon. A ship is about to set sail and you are responsible for its safety precautions. More specifically, you are responsible for determining how many life rafts to carry onboard. You are given a list of all the passengers\' weights and are informed that a single life raft has a maximum capacity of limit and can hold at most two people. Return the minimum number of life rafts you must take onboard to ensure the safety of all your passengers.","permalink":"/leetcode/pt-BR/docs/problems/boats-to-save-people"},{"id":"problems/bricks-in-wheelbarrow","title":"Bricks in Wheelbarrow","description":"You are transporting bricks on a construction site and want to work as efficiently as possible. The weight of each brick is given by bricks[i]. Given a wheelbarrow that can carry up to (not including) 5000 pounds, return the maximum number of bricks you can place in your wheelbarrow to transport.","permalink":"/leetcode/pt-BR/docs/problems/bricks-in-wheelbarrow"},{"id":"problems/coin-change","title":"Coin Change","description":"This question is asked by Facebook. Given an array that represents different coin denominations and an amount of change you need to make, return the fewest number of coins it takes to make the given amount of change.","permalink":"/leetcode/pt-BR/docs/problems/coin-change"},{"id":"problems/container-with-most-water","title":"Container With Most Water","description":"You are building a pool in your backyard and want to create the largest pool possible. The largest pool is defined as the pool that holds the most water. The workers you hired to dig the hole for your pool didn\'t do a great job and because of this the depths of the pool at different areas are not equal. Given an integer array of non-negative integers that represents a histogram of the different heights at each position of the hole for your pool, return the largest pool you can create.","permalink":"/leetcode/pt-BR/docs/problems/container-with-most-water"},{"id":"problems/is-subsequence","title":"Is Subsequence","description":"This question is asked by Google. Given two strings s and t, return whether or not s is a subsequence of t.","permalink":"/leetcode/pt-BR/docs/problems/is-subsequence"},{"id":"problems/labeled-items-max-sum","title":"Labeled Items Maximum Sum","description":"You are given a list of values and a list of labels. The ith element in labels represents the label of the ith element. Similarly, the ith element in values represents the value associated with the ith element (i.e. together, an \\"item\\" could be thought of as a label and a price).","permalink":"/leetcode/pt-BR/docs/problems/labeled-items-max-sum"},{"id":"problems/lemonade-change","title":"Lemonade Change","description":"This question is asked by Amazon. You\'re running a popsicle stand where each popsicle costs $5. Each customer you encountered pays with either a $5 bill, a $10 bill, or a $20 bill and only buys a single popsicle. The customers that come to your stand come in the ordered given by the customers array where customers[i] represents the bill the ith customer pays with. Starting with $0, return whether or not you can serve all the given customers while also giving the correct amount of change.","permalink":"/leetcode/pt-BR/docs/problems/lemonade-change"},{"id":"problems/maximum-points-from-coins","title":"Maximum Points You Can Obtain","description":"This question is asked by Google. You are given a bag of coins, an initial energy of E, and want to maximize your number of points (which starts at zero). To gain a single point you can exchange coins[i] amount of energy (i.e. if I have 100 energy and a coin that has a value 50 I can exchange 50 energy to gain a point). If you do not have enough energy you can give away a point in exchange for an increase in energy by coins[i] amount (i.e. you give away a point and your energy is increased by the value of that coin: energy += coins[i]). Return the maximum number of points you can gain.","permalink":"/leetcode/pt-BR/docs/problems/maximum-points-from-coins"},{"id":"problems/partition-labels","title":"Partition Labels","description":"Given a string s containing only lowercase characters, return a list of integers representing the size of each substring you can create such that each character in s only appears in one substring.","permalink":"/leetcode/pt-BR/docs/problems/partition-labels"},{"id":"problems/reorganize-string","title":"Reorganize String","description":"This question is asked by Facebook. Given a string, check if it can be modified such that no two adjacent characters are the same. If it is possible, return any string that satisfies this condition and if it is not possible return an empty string.","permalink":"/leetcode/pt-BR/docs/problems/reorganize-string"},{"id":"problems/two-city-scheduling","title":"Two City Scheduling","description":"This question is asked by Google. A company is booking flights to send its employees to its two satellite offices A and B. The cost of sending the ith employee to office A and office B is given by pricesi and pricesi respectively. Given that half the employees must be sent to office A and half the employees must be sent to office B, return the minimum cost the company must pay for all their employees\' flights.","permalink":"/leetcode/pt-BR/docs/problems/two-city-scheduling"}],"unlisted":false}}')}}]);